result:
הכנתי עבורך סוכן n8n למעקב אחרי הוצאות, המבוסס על מסננים ותהליכים שצוינו.

```json
{
 "name": "מעקב אחרי הוצאות",
 "version": 1,
 "nodes": [
 {
 "id": "1",
 "name": "Webhook",
 "type": "n8n-nodes-base.webhook",
 "typeVersion": 1,
 "position": [250, 300],
 "parameters": {
 "path": "track-expense"
 }
 },
 {
 "id": "2",
 "name": "Set Expense Data",
 "type": "n8n-nodes-base.set",
 "typeVersion": 1,
 "position": [500, 300],
 "parameters": {
 "rules": {
 "amount": {
 "value": "={{ $json.amount }}"
 },
 "category": {
 "value": "={{ $json.category }}"
 },
 "date": {
 "value": "={{ $json.date }}"
 }
 }
 }
 },
 {
 "id": "3",
 "name": "Check Amount",
 "type": "n8n-nodes-base.if",
 "typeVersion": 1,
 "position": [750, 300],
 "parameters": {
 "conditions": {
 "number": [
 {
 "value1": "={{ $json.amount }}",
 "operation": "lessThanOrEqual",
 "value2": "50"
 }
 ]
 }
 }
 },
 {
 "id": "4",
 "name": "Log Low Expense",
 "type": "n8n-nodes-base.code",
 "typeVersion": 1,
 "position": [1000, 250],
 "parameters": {
 "jsCode": "const log = `הוצאה נמוכה: {{ $json.amount }} ₪ בקטגוריה {{ $json.category }}`; console.log(log); return [ { json: { message: log } } ];"
 }
 },
 {
 "id": "5",
 "name": "Log High Expense",
 "type": "n8n-nodes-base.code",
 "typeVersion": 1,
 "position": [1000, 350],
 "parameters": {
 "jsCode": "const log = `הוצאה גבוהה: {{ $json.amount }} ₪ בקטגוריה {{ $json.category }}`; console.log(log); return [ { json: { message: log } } ];"
 }
 },
 {
 "id": "6",
 "name": "Google Sheets",
 "type": "n8n-nodes-base.googleSheets",
 "typeVersion": 1,
 "position": [1250, 300],
 "parameters": {
 "sheetId": "",
 "range": "A1:D1",
 "operation": "appendRow"
 },
 "credentials": {
 "googleSheetsOAuth2Api": {}
 }
 }
 ],
 "connections": {
 "Webhook": {
 "main": [
 [
 {
 "node": "Set Expense Data",
 "type": "main",
 "index": 0
 }
 ]
 ]
 },
 "Set Expense Data": {
 "main": [
 [
 {
 "node": "Check Amount",
 "type": "main",
 "index": 0
 }
 ]
 ]
 },
 "Check Amount": {
 "main": [
 [
 {
 "node": "Log Low Expense",
 "type": "main",
 "index": 0
 }
 ],
 [
 {
 "node": "Log High Expense",
 "type": "main",
 "index": 0
 }
 ]
 ]
 },
 "Log Low Expense": {
 "main": [
 [
 {
 "node": "Google Sheets",
 "type": "main",
 "index": 0
 }
 ]
 ]
 },
 "Log High Expense": {
 "main": [
 [
 {
 "node": "Google Sheets",
 "type": "main",
 "index": 0
 }
 ]
 ]
 }
 }
}
```
